const walletInfo  = $('Whale Wallet List').item.json;
const transfers   = $('Get Token Transfers').item.json;
const balanceData = $input.item.json;

const CHAIN_META = {
  eth:      { icon: '⟠', name: 'Ethereum',  nativeSymbol: 'ETH',   decimals: 18, price: 3500 },
  bsc:      { icon: '◈', name: 'BNB Chain', nativeSymbol: 'BNB',   decimals: 18, price: 600  },
  polygon:  { icon: '⬡', name: 'Polygon',   nativeSymbol: 'MATIC', decimals: 18, price: 0.9  },
  arbitrum: { icon: '🔵', name: 'Arbitrum',  nativeSymbol: 'ETH',   decimals: 18, price: 3500 },
};

const STABLECOINS = ['usdt','usdc','busd','dai','tusd','usdp','frax'];
const chain   = CHAIN_META[walletInfo.chain] || { icon: '🔗', name: walletInfo.chain, nativeSymbol: '?', decimals: 18, price: 1 };
const txList  = (transfers.result || []);
const short   = walletInfo.address.slice(0,6) + '...' + walletInfo.address.slice(-4);
const nativeBal = parseFloat(balanceData.balance || '0') / Math.pow(10, chain.decimals);

const qualifyingTxs = txList.filter(tx => {
  const dec      = parseInt(tx.token_decimals || 18);
  const amount   = parseFloat(tx.value || '0') / Math.pow(10, dec);
  const sym      = (tx.token_symbol || '').toLowerCase();
  const isStable = STABLECOINS.includes(sym);
  const usdEst   = isStable ? amount : amount * chain.price;
  return usdEst >= 500000;
});

if (qualifyingTxs.length === 0) return { json: { skip: true, message: null } };

const tx       = qualifyingTxs[0];
const dec      = parseInt(tx.token_decimals || 18);
const amount   = parseFloat(tx.value || '0') / Math.pow(10, dec);
const sym      = (tx.token_symbol || chain.nativeSymbol).toUpperCase();
const isStable = STABLECOINS.includes((tx.token_symbol || '').toLowerCase());
const usdEst   = isStable ? amount : amount * chain.price;

let tierLabel, tierEmoji;
if      (usdEst >= 5000000) { tierLabel = 'MEGA WHALE 🦣'; tierEmoji = '🚨'; }
else if (usdEst >= 1000000) { tierLabel = 'LARGE WHALE 🐋'; tierEmoji = '⚠️'; }
else                         { tierLabel = 'WHALE 🐳';       tierEmoji = '📡'; }

const walletLC    = walletInfo.address.toLowerCase();
const isReceiving = (tx.to_address   || '').toLowerCase() === walletLC;
const isSending   = (tx.from_address || '').toLowerCase() === walletLC;

let signal, moodEmoji;
if      (isReceiving) { signal = '📈 Receiving — Bullish accumulation'; moodEmoji = '🟢'; }
else if (isSending)   { signal = '📉 Sending — Potential distribution';  moodEmoji = '🔴'; }
else                  { signal = '⚪ Neutral movement';                   moodEmoji = '⚪'; }

const fmtUsd  = n => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
const fmtAmt  = new Intl.NumberFormat('en-US', { maximumFractionDigits: 2 }).format(amount);
const timeStr = new Date(tx.block_timestamp || Date.now()).toUTCString().replace(' GMT', ' UTC');
const divider = '───────────────────────';

const message =
  tierEmoji + ' ' + chain.icon + ' <b>' + chain.name + ' ' + tierLabel + '</b> ' + moodEmoji + '\n' +
  divider + '\n' +
  '💰 <b>' + fmtAmt + ' ' + sym + '</b>\n' +
  '💵 Est. Value: <b>' + fmtUsd(usdEst) + '</b>\n' +
  '👛 Wallet: <code>' + short + '</code>\n' +
  '🏷 Label: <i>' + walletInfo.label + '</i>\n' +
  '📤 From: <code>' + (tx.from_address||'').slice(0,10) + '...</code>\n' +
  '📥 To:   <code>' + (tx.to_address||'').slice(0,10) + '...</code>\n' +
  divider + '\n' +
  '📊 ' + signal + '\n' +
  '💼 Balance: <b>' + nativeBal.toFixed(2) + ' ' + chain.nativeSymbol + '</b>\n' +
  divider + '\n' +
  '⏰ <i>' + timeStr + '</i>';

return { json: { message, signal, skip: false, tier: tierLabel, chain: walletInfo.chain, symbol: sym, usdEst, wallet: short } };
